// Extract JSON from Claude's response
const response = $input.first().json.response;

// Try to parse the response
let courseData;

try {
  // Check if response contains markdown code blocks
  const jsonMatch = response.match(/```(?:json)?\s*([\s\S]*?)```/);

  if (jsonMatch) {
    // Extract JSON from code block
    courseData = JSON.parse(jsonMatch[1].trim());
  } else {
    // Try to parse directly
    courseData = JSON.parse(response);
  }

  // Validate required fields
  if (!courseData.course || !courseData.course.title) {
    throw new Error('Missing course title');
  }

  if (!courseData.lessons || courseData.lessons.length === 0) {
    throw new Error('No lessons provided');
  }

  // Ensure all lessons have required fields
  courseData.lessons.forEach((lesson, index) => {
    if (!lesson.title) {
      throw new Error(`Lesson ${index} missing title`);
    }
    if (lesson.order === undefined) {
      lesson.order = index;
    }
    if (!lesson.content_markdown) {
      throw new Error(`Lesson ${index} missing content_markdown`);
    }
  });

  return {
    json: courseData
  };

} catch (error) {
  throw new Error(`Failed to parse Claude response: ${error.message}\n\nResponse: ${response}`);
}
